	force?: boolean;
}

export interface DockerContainerInfo {
	id: string;
	name: string;
	image: string;
	status: 'running' | 'stopped';
	network: string;
	/** Ports published to the host. HALO containers never publish ports — always empty. */
	publishedPorts: Record<string, unknown>;
}

